namespace FP2Practica1{internal class Program{const int maxMem = 10;struct Coor{public int ver, hor;}struct Jugada{public Coor aca; public Coor emp;}struct Memoria{public Jugada[] Jugadas; public int ind;}struct Estado{public char[,] mat; public char obj; public Coor act, sal; public bool sel;}static void Main(){Memoria memoria; memoria.Jugadas = new Jugada[maxMem]; int level;Estado est; bool hayJuego = true, victoria = false; StreamWriter sw = new StreamWriter("record.txt", true);sw.Close();while (hayJuego){memoria.ind = 0;Console.Write("¿Qué nivel desea jugar?: ");level = int.Parse(Console.ReadLine());Console.CursorVisible = false; Console.Clear();est = LeeEst("levels.txt", level);MarcaSalida(ref est);victoria = false;Render(est);while (hayJuego && !victoria){char c = LeeInput();if (c == 'q') { hayJuego = false; } else { ProcesaInput(ref est, c, ref memoria); }Render(est);if (est.mat[est.sal.ver, est.sal.hor] == est.obj) victoria = true;}if (victoria){Console.WriteLine("GANASTE");Record(memoria, level);}else{Console.Clear();Console.WriteLine("Juego Abortado :(");}}}static void Delete(ref Memoria mem, ref Estado est){if (mem.ind > 0){Coor dir;mem.ind--; dir.hor = mem.Jugadas[mem.ind % maxMem].emp.hor - mem.Jugadas[mem.ind % maxMem].aca.hor;dir.ver = mem.Jugadas[mem.ind % maxMem].emp.ver - mem.Jugadas[mem.ind % maxMem].aca.ver;if (!(dir.hor == 0 && dir.ver == 0)){est.act.hor = mem.Jugadas[mem.ind % maxMem].aca.hor;est.act.ver = mem.Jugadas[mem.ind % maxMem].aca.ver;est.sel = true;MueveBloque(ref est, dir, ref mem, false);est.sel = false;}mem.Jugadas[mem.ind % maxMem].aca.hor = mem.Jugadas[mem.ind % maxMem].emp.hor;mem.Jugadas[mem.ind % maxMem].aca.ver = mem.Jugadas[mem.ind % maxMem].emp.ver;}}static Estado LeeEst(string file, int n){Estado nivel; nivel.sel = false; nivel.sal.hor = 0; nivel.sal.ver = 0; StreamReader File = new StreamReader(file);string l = "level " + n; while (File.ReadLine() != l) ; nivel.obj = char.Parse(File.ReadLine()); bool espacio = false; string tablero = ""; string linea; bool numColumna = false; int numCol = 0; int numFilas = 0; while (!espacio){linea = File.ReadLine() + ' ';if (!numColumna) { numColumna = true; numCol = linea.Length - 1; }if (linea == " ") espacio = true; else { tablero += linea; numFilas++; }}nivel.mat = new char[numCol + 2, numFilas + 2]; string[] lineas = tablero.Split(' '); for (int i = 0; i < nivel.mat.GetLength(1); i++) nivel.mat[0, i] = '#'; for (int fila = 1; fila < nivel.mat.GetLength(0) - 1; fila++){nivel.mat[fila, 0] = '#'; for (int colu = 1; colu < nivel.mat.GetLength(1) - 1; colu++){nivel.mat[fila, colu] = lineas[fila - 1][colu - 1];}nivel.mat[fila, nivel.mat.GetLength(1) - 1] = '#';}for (int u = 0; u < nivel.mat.GetLength(1); u++) nivel.mat[nivel.mat.GetLength(0) - 1, u] = '#'; nivel.act.hor = 1; nivel.act.ver = 1;File.Close();return nivel;}static void MarcaSalida(ref Estado est){int fila, colu; int i = 0; int j = 0;Coor bloqObj; bloqObj.hor = 0; bloqObj.ver = 0; bool encontrado = false;while (i < est.mat.GetLength(1) && !encontrado){j = 0;while (j < est.mat.GetLength(0) && !encontrado){if (est.mat[i, j] == est.obj) { encontrado = true; bloqObj.ver = i; bloqObj.hor = j; }j++;}i++;}if (est.mat[bloqObj.ver + 1, bloqObj.hor] == est.obj) { colu = bloqObj.hor; fila = est.mat.GetLength(0) - 1; } else { colu = est.mat.GetLength(0) - 1; fila = bloqObj.ver; }est.sal.hor = colu; est.sal.ver = fila; est.mat[fila, colu] = '.';}static void Render(Estado est){ConsoleColor[] colores = (ConsoleColor[])ConsoleColor.GetValues(typeof(ConsoleColor));Console.SetCursorPosition(0, 0);for (int i = 0; i < est.mat.GetLength(0); i++){for (int j = 0; j < est.mat.GetLength(1); j++){if (est.mat[i, j] == '#') Console.BackgroundColor = colores[colores.GetLength(0) - 1];else if (est.mat[i, j] == '.') Console.BackgroundColor = colores[0];else Console.BackgroundColor = colores[BloqueToInt(est.mat[i, j])];Console.Write("  ");}Console.WriteLine();}if (est.mat[est.act.ver, est.act.hor] == '.') Console.BackgroundColor = colores[0];else Console.BackgroundColor = colores[BloqueToInt(est.mat[est.act.ver, est.act.hor])];Console.SetCursorPosition(est.act.hor * 2, est.act.ver);if (est.sel) Console.WriteLine("<>");else Console.WriteLine("**");if (est.mat[est.sal.ver, est.sal.hor] != est.obj){Console.SetCursorPosition(est.sal.hor * 2, est.sal.ver);Console.BackgroundColor = colores[0]; Console.Write("  ");}Console.SetCursorPosition(0, est.mat.GetLength(0) + 3);Console.ResetColor();Console.Write("Objetivo: ");Console.BackgroundColor = colores[BloqueToInt(est.obj)];Console.WriteLine("  ");Console.ResetColor();}static int BloqueToInt(char c){return ((int)c) - ((int)'a') + 1;}static void MueveCursor(ref Estado est, Coor dir){if (est.act.hor + dir.hor >= 1 && est.act.hor + dir.hor < est.mat.GetLength(0) - 1) est.act.hor += dir.hor; if (est.act.ver + dir.ver >= 1 && est.act.ver + dir.ver < est.mat.GetLength(1) - 1) est.act.ver += dir.ver;}static void MueveBloque(ref Estado est, Coor dir, ref Memoria mem, bool registro){if (est.sel){Coor negdir = dir; negdir.hor *= -1; negdir.ver *= -1; Coor cabeza = BuscaCabeza(dir, est); Coor cola = BuscaCabeza(negdir, est); char c = est.mat[cabeza.ver, cabeza.hor]; if ((cola.hor != cabeza.hor || cola.ver != cabeza.ver) && est.mat[cabeza.ver + dir.ver, cabeza.hor + dir.hor] == '.'){est.mat[cola.ver, cola.hor] = '.'; est.mat[cabeza.ver + dir.ver, cabeza.hor + dir.hor] = c; if (registro){mem.Jugadas[mem.ind % maxMem].emp.hor = est.act.hor;mem.Jugadas[mem.ind % maxMem].emp.ver = est.act.ver;}MueveCursor(ref est, dir); if (registro){mem.Jugadas[mem.ind % maxMem].aca.hor = est.act.hor; mem.Jugadas[mem.ind % maxMem].aca.ver = est.act.ver;mem.ind++;}}}}static Coor BuscaCabeza(Coor dir, Estado est){Coor pos = est.act; Coor cabeza = pos; char c = est.mat[pos.ver, pos.hor]; while (est.mat[pos.ver + dir.ver, pos.hor + dir.hor] == c){pos.hor += dir.hor; pos.ver += dir.ver; cabeza = pos;}return cabeza;}static void Mueve(int hor, int ver, ref Estado est, ref Memoria mem){Coor dir;dir.hor = hor; dir.ver = ver;if (est.sel) MueveBloque(ref est, dir, ref mem, true);else MueveCursor(ref est, dir);}static void ProcesaInput(ref Estado est, char c, ref Memoria mem){Coor pos = est.act; switch (c){case 's':if (est.mat[pos.ver, pos.hor] != '#' && est.mat[pos.ver, pos.hor] != '.') est.sel = !est.sel; break;case 'u':Mueve(0, -1, ref est, ref mem);break;case 'd':Mueve(0, 1, ref est, ref mem);break;case 'l':Mueve(-1, 0, ref est, ref mem);break;case 'r':Mueve(1, 0, ref est, ref mem);break;case 'z':Delete(ref mem, ref est);break;default: break;}}static char LeeInput(){char d = ' ';while (d == ' '){if (Console.KeyAvailable){string tecla = Console.ReadKey().Key.ToString();switch (tecla){case "LeftArrow": d = 'l'; break;case "UpArrow": d = 'u'; break;case "RightArrow": d = 'r'; break;case "DownArrow": d = 'd'; break;case "Delete": d = 'z'; break;case "Escape": d = 'q'; break;case "Spacebar": d = 's'; break;}}}return d;}static void Record(Memoria mem, int level){StreamReader sr = new StreamReader("record.txt"); bool encontrado = false; while (!encontrado && !sr.EndOfStream){if (sr.ReadLine() == "level " + level) { encontrado = true; }}if (encontrado){int OldMoves = int.Parse(sr.ReadLine()); sr.Close(); if (mem.ind < OldMoves){EstableceRecord(level, mem.ind);}}else{sr.Close();StreamWriter sw = new StreamWriter("record.txt", true);sw.WriteLine("level " + level);sw.WriteLine(mem.ind);sw.Close();}}static void EstableceRecord(int level, int NewMoves){StreamReader sr = new StreamReader("record.txt");StreamWriter sw = new StreamWriter("newrecord.txt");bool encontrado = false; while (!encontrado && !sr.EndOfStream){string s = sr.ReadLine();if (s == $"level {level}"){encontrado = true;}sw.WriteLine(s);}sw.WriteLine(NewMoves);sr.ReadLine();while (!sr.EndOfStream){string s = sr.ReadLine();sw.WriteLine(s);}sr.Close();sw.Close();File.Replace("newrecord.txt", "record.txt", null);Console.WriteLine($"Nuevo record para el nivel {level}!!!!!! felicidades ");}}}